-- Write your PostgreSQL query statement below
SELECT r.student_id AS student_id, r.subject AS subject, s1.score AS first_score, s2.score AS latest_score FROM (SELECT m1.student_id, m1.subject, m1.first_date, m2.latest_date FROM (SELECT r1.student_id, r1.subject, MIN(r2.exam_date) AS first_date FROM Scores AS r2 INNER JOIN (SELECT student_id, subject FROM Scores GROUP BY student_id, subject HAVING COUNT(score) > 1) AS r1 ON r1.student_id = r2.student_id AND r1.subject = r2.subject GROUP BY r1.student_id, r1.subject) AS m1 INNER JOIN (SELECT r1.student_id, r1.subject, MAX(r2.exam_date) AS latest_date FROM Scores AS r2 INNER JOIN (SELECT student_id, subject FROM Scores GROUP BY student_id, subject HAVING COUNT(score) > 1) AS r1 ON r1.student_id = r2.student_id AND r1.subject = r2.subject GROUP BY r1.student_id, r1.subject) AS m2 ON m1.student_id = m2.student_id AND m1.subject = m2.subject) AS r INNER JOIN Scores AS s1 ON s1.student_id = r.student_id AND s1.subject = r.subject AND s1.exam_date = r.first_date INNER JOIN Scores AS s2 ON s2.student_id = r.student_id AND s2.subject = r.subject AND s2.exam_date = r.latest_date WHERE s1.score < s2.score ORDER BY r.student_id, r.subject

-- Write your MySQL query statement below
SELECT r.student_id AS student_id, r.subject AS subject, s1.score AS first_score, s2.score AS latest_score FROM (SELECT m1.student_id, m1.subject, m1.first_date, m2.latest_date FROM (SELECT r1.student_id, r1.subject, MIN(r2.exam_date) AS first_date FROM Scores AS r2 INNER JOIN (SELECT student_id, subject FROM Scores GROUP BY student_id, subject HAVING COUNT(score) > 1) AS r1 ON r1.student_id = r2.student_id AND r1.subject = r2.subject GROUP BY r1.student_id, r1.subject) AS m1 INNER JOIN (SELECT r1.student_id, r1.subject, MAX(r2.exam_date) AS latest_date FROM Scores AS r2 INNER JOIN (SELECT student_id, subject FROM Scores GROUP BY student_id, subject HAVING COUNT(score) > 1) AS r1 ON r1.student_id = r2.student_id AND r1.subject = r2.subject GROUP BY r1.student_id, r1.subject) AS m2 ON m1.student_id = m2.student_id AND m1.subject = m2.subject) AS r INNER JOIN Scores AS s1 ON s1.student_id = r.student_id AND s1.subject = r.subject AND s1.exam_date = r.first_date INNER JOIN Scores AS s2 ON s2.student_id = r.student_id AND s2.subject = r.subject AND s2.exam_date = r.latest_date WHERE s1.score < s2.score ORDER BY r.student_id, r.subject